import{_ as r,o as a,c as t,ag as s}from"./chunks/framework.CAXxHpAX.js";const m=JSON.parse('{"title":"Fase 2: HCI-platform — compute & storage fundament","description":"","frontmatter":{"title":"Fase 2: HCI-platform — compute & storage fundament","phase":2,"topic":"infrastruktur","personas":["arkitekt","driftsleder"],"tags":["HCI","compute","storage","hyperkonvergent","klynge","skalering"],"priority":"kritisk-sti","dependencies":[1]},"headers":[],"relativePath":"faser/02-hci.md","filePath":"faser/02-hci.md"}'),n={name:"faser/02-hci.md"};function o(i,e,p,d,l,g){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="fase-2-hci-platform-—-compute-storage-fundament" tabindex="-1">Fase 2: HCI-platform — compute &amp; storage fundament <a class="header-anchor" href="#fase-2-hci-platform-—-compute-storage-fundament" aria-label="Permalink to &quot;Fase 2: HCI-platform — compute &amp; storage fundament&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="critical-path-badge">Kritisk sti</span></span><span><strong>Afhænger af:</strong> Fase 1 (netværk)</span><span><strong>Blokerer:</strong> Fase 3</span></div><div class="persona-badges"><span class="persona-badge arkitekt">🏗️ Arkitekt</span><span class="persona-badge driftsleder">⚙️ Driftsleder</span></div><p>Det forventes, at den hyperkonvergente platform udgør det samlede compute- og storage-fundament, hvor processorkraft, hukommelse og lagringskapacitet leveres som en integreret, skalerbar enhed.</p><ul><li><p>HCI-noder deployed i klynger på begge primære sites med identisk eller ækvivalent kapacitet, så hvert site kan håndtere den fulde workload ved failover (N-1 site-kapacitet).</p></li><li><p>Storage-laget konfigureres med den påkrævede redundans (typisk RF2 eller RF3 / erasure coding) for at sikre dataintegritet ved tab af individuelle diske eller noder.</p></li><li><p>Compute-ressourcer organiseres i ressourcepools med definerede kapacitetsgrænser pr. tenant, håndhævet via policies for at forhindre ressource-overforbrug.</p></li><li><p>Platformen designes til horisontal skalering: tilføjelse af nye noder skal være en standardiseret, ikke-disruptiv operation, der øger både compute og storage proportionelt.</p></li><li><p>Hypervisor og HCI-management konfigureres med høj tilgængelighed, så tab af management-komponenter ikke påvirker den løbende drift af workloads.</p></li></ul>',5)])])}const c=r(n,[["render",o]]);export{m as __pageData,c as default};
